import Main from "./Components/main/index"

const About = () => {
  return (
    <>
      <h2>About</h2>
    </>
  );
};

function App() {


  return (
    <div className="App">
      <Router>
        <nav>
          <Navbar/>
        </nav>

        <main>
          <Main/>
        </main>

      </Router>
    </div>
  );
}

export default App;
